import { Router } from "express";
import { UserRole } from "../../../generated/prisma/enums";
import authCheck from "../../middleware/authCheck";
import requestValidator from "../../middleware/requestValidator";
import { DishController } from "./dish.controller";
import { createDishSchema, updateDishSchema } from "./dish.validation";
import { multerUpload } from "../../../config/multerConfig";
const router = Router();
router.post("/", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), multerUpload.single("image"), requestValidator(createDishSchema), DishController.createDish);
router.get("/", DishController.getDishes);
router.get("/me", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), DishController.getMyDishes);
router.get("/trending", DishController.getTrendingDishes);
router.get("/restaurants/:restaurantId/trending", DishController.getTrendingDishesByRestaurant);
router.get("/:id", DishController.getDishById);
router.patch("/me/:id", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), requestValidator(updateDishSchema), multerUpload.single("image"), DishController.updateMyDish);
router.delete("/me/:id", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), DishController.deleteMyDish);
router.patch("/:id", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), requestValidator(updateDishSchema), multerUpload.single("image"), DishController.updateDish);
router.delete("/:id", authCheck(UserRole.ADMIN, UserRole.SUPER_ADMIN, UserRole.OWNER, UserRole.CONSUMER), DishController.deleteDish);
export const dishRoute = router;
